interface.definition:
if(
  ri!style = "SECTION",
  #"SYSTEM_SYSRULES_sectionLayout_v1"(
    label: a!defaultValue(ri!label, "Das passiert jetzt"),
    labelIcon: "route",
    contents: {
      #"SYSTEM_SYSRULES_richTextDisplayField"(
        align: a!defaultValue(ri!align, "LEFT"),
        labelPosition: "COLLAPSED",
        value: {
          if(
            count(ri!text) > 1,
            #"SYSTEM_SYSRULES_richTextBulletedList"(
              items: ri!text
            ),
            ri!text
          )
        }
      )
    },
    showWhen: ri!showWhen <> false,
    divider: "ABOVE",
    labelSize: a!defaultValue(ri!labelSize, "MEDIUM")
  ),
  #"SYSTEM_SYSRULES_cardLayout"(
    contents: {
      #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1615202"(
        align: a!defaultValue(ri!align, "LEFT"),
        value: {
          #"SYSTEM_SYSRULES_richTextIcon"(
            icon: "route",
            size: a!defaultValue(ri!labelSize, "STANDARD")
          ),
          "  ",
          #"SYSTEM_SYSRULES_richTextItem_v1"(
            text: a!defaultValue(ri!label, "Das passiert jetzt"),
            style: "STRONG",
            size: a!defaultValue(ri!labelSize, "STANDARD")
          ),
          #"SYSTEM_SYSRULES_richTextItem_v1"(
            text: char(10) & ri!text,
            size: a!defaultValue(ri!textSize, "STANDARD"),
            showWhen: count(ri!text) = 1
          )
        }
      ),
      #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1615202"(
        align: a!defaultValue(ri!align, "LEFT"),
        value: #"SYSTEM_SYSRULES_richTextBulletedList"(
          items: #"SYSTEM_SYSRULES_forEach"(
            items: ri!text,
            expression: #"SYSTEM_SYSRULES_richTextItem_v1"(
              text: fv!item,
              size: a!defaultValue(ri!textSize, "STANDARD")
            )
          )
        ),
        showWhen: count(ri!text) > 1
      )
    },
    showWhen: ri!showWhen <> false,
    style: a!defaultValue(ri!backgroundColor, "INFO"),
    shape: a!defaultValue(ri!shape, "SEMI_ROUNDED"),
    marginBelow: "STANDARD",
    showBorder: a!defaultValue(ri!showBorder, false),
    showShadow: a!defaultValue(ri!showShadow, true)
  )
)
